/**
 * Menu Service Tests
 *
 * Unit tests for MenuService covering:
 * - Menu CRUD operations
 * - Publishing and unpublishing
 * - Settings management
 * - Menu duplication
 * - Slug validation
 *
 * @module modules/menu/__tests__/menu.service.spec
 */

import { describe, it, expect, beforeEach, vi, type Mock } from 'vitest';

import { MenuService } from '@/modules/menu/menu.service';
import { AppException } from '@/core/exceptions/app.exception';
import type { MenuRepository, PaginatedResult } from '@/modules/menu/menu.repository';
import type { EventService } from '@/core/services/event.service';
import type { Menu, MenuWithRelations, MenuSettings } from '@/modules/menu/menu.types';

// -----------------------------------------------------------------------------
// Mock Factories
// -----------------------------------------------------------------------------

/**
 * Creates a mock MenuRepository
 */
function createMockRepository(): {
  findAll: Mock;
  findAllSummaries: Mock;
  findById: Mock;
  findByIdWithRelations: Mock;
  findByIdOrThrow: Mock;
  findBySlug: Mock;
  findDefaultMenu: Mock;
  findPublished: Mock;
  slugExists: Mock;
  count: Mock;
  create: Mock;
  update: Mock;
  updateSettings: Mock;
  publish: Mock;
  unpublish: Mock;
  setAsDefault: Mock;
  duplicate: Mock;
  softDelete: Mock;
  restore: Mock;
} {
  return {
    findAll: vi.fn(),
    findAllSummaries: vi.fn(),
    findById: vi.fn(),
    findByIdWithRelations: vi.fn(),
    findByIdOrThrow: vi.fn(),
    findBySlug: vi.fn(),
    findDefaultMenu: vi.fn(),
    findPublished: vi.fn(),
    slugExists: vi.fn(),
    count: vi.fn(),
    create: vi.fn(),
    update: vi.fn(),
    updateSettings: vi.fn(),
    publish: vi.fn(),
    unpublish: vi.fn(),
    setAsDefault: vi.fn(),
    duplicate: vi.fn(),
    softDelete: vi.fn(),
    restore: vi.fn(),
  };
}

/**
 * Creates a mock EventService
 */
function createMockEventService(): {
  emitCustom: Mock;
} {
  return {
    emitCustom: vi.fn(),
  };
}

/**
 * Creates a mock menu for testing
 */
function createMockMenu(overrides: Partial<Menu> = {}): Menu {
  return {
    id: 'menu_123',
    organizationId: 'org_123',
    branchId: null,
    themeId: null,
    name: 'Test Menu',
    slug: 'test-menu',
    description: 'A test menu',
    isPublished: false,
    isDefault: true,
    publishedAt: null,
    settings: {},
    sortOrder: 0,
    createdAt: new Date(),
    updatedAt: new Date(),
    deletedAt: null,
    ...overrides,
  };
}

/**
 * Creates a mock menu with relations
 */
function createMockMenuWithRelations(
  overrides: Partial<MenuWithRelations> = {}
): MenuWithRelations {
  return {
    ...createMockMenu(),
    theme: null,
    categories: [],
    qrCodes: [],
    _count: { categories: 0 },
    ...overrides,
  };
}

// -----------------------------------------------------------------------------
// Test Suite
// -----------------------------------------------------------------------------

describe('MenuService', () => {
  let service: MenuService;
  let mockRepository: ReturnType<typeof createMockRepository>;
  let mockEventService: ReturnType<typeof createMockEventService>;

  const orgId = 'org_123';

  beforeEach(() => {
    mockRepository = createMockRepository();
    mockEventService = createMockEventService();

    service = new MenuService(
      mockRepository as unknown as MenuRepository,
      mockEventService as unknown as EventService
    );
  });

  // ---------------------------------------------------------------------------
  // Read Operations Tests
  // ---------------------------------------------------------------------------

  describe('list', () => {
    it('should return paginated menus', async () => {
      // Arrange
      const menus = [createMockMenu(), createMockMenu({ id: 'menu_456' })];
      const paginatedResult: PaginatedResult<Menu> = {
        data: menus,
        meta: { page: 1, perPage: 20, total: 2, totalPages: 1 },
      };
      mockRepository.findAll.mockResolvedValue(paginatedResult);

      // Act
      const result = await service.list(orgId, { page: 1, perPage: 20 });

      // Assert
      expect(result).toEqual(paginatedResult);
      expect(mockRepository.findAll).toHaveBeenCalledWith(
        orgId,
        expect.objectContaining({ page: 1, perPage: 20 })
      );
    });

    it('should apply filters when provided', async () => {
      // Arrange
      const paginatedResult: PaginatedResult<Menu> = {
        data: [createMockMenu({ isPublished: true })],
        meta: { page: 1, perPage: 20, total: 1, totalPages: 1 },
      };
      mockRepository.findAll.mockResolvedValue(paginatedResult);

      // Act
      await service.list(orgId, { isPublished: true });

      // Assert
      expect(mockRepository.findAll).toHaveBeenCalledWith(
        orgId,
        expect.objectContaining({ isPublished: true })
      );
    });
  });

  describe('getById', () => {
    it('should return menu when found', async () => {
      // Arrange
      const menu = createMockMenu();
      mockRepository.findById.mockResolvedValue(menu);

      // Act
      const result = await service.getById(orgId, 'menu_123');

      // Assert
      expect(result).toEqual(menu);
      expect(mockRepository.findById).toHaveBeenCalledWith('menu_123', orgId);
    });

    it('should return null when menu not found', async () => {
      // Arrange
      mockRepository.findById.mockResolvedValue(null);

      // Act
      const result = await service.getById(orgId, 'nonexistent');

      // Assert
      expect(result).toBeNull();
    });
  });

  describe('getByIdWithRelations', () => {
    it('should return menu with relations when found', async () => {
      // Arrange
      const menuWithRelations = createMockMenuWithRelations();
      mockRepository.findByIdWithRelations.mockResolvedValue(menuWithRelations);

      // Act
      const result = await service.getByIdWithRelations(orgId, 'menu_123');

      // Assert
      expect(result).toEqual(menuWithRelations);
    });

    it('should throw AppException when menu not found', async () => {
      // Arrange
      mockRepository.findByIdWithRelations.mockResolvedValue(null);

      // Act & Assert
      await expect(
        service.getByIdWithRelations(orgId, 'nonexistent')
      ).rejects.toThrow(AppException);
    });
  });

  describe('getBySlug', () => {
    it('should return menu when found by slug', async () => {
      // Arrange
      const menu = createMockMenu();
      mockRepository.findBySlug.mockResolvedValue(menu);

      // Act
      const result = await service.getBySlug(orgId, 'test-menu');

      // Assert
      expect(result).toEqual(menu);
      expect(mockRepository.findBySlug).toHaveBeenCalledWith(orgId, 'test-menu');
    });
  });

  describe('getDefaultMenu', () => {
    it('should return default menu when exists', async () => {
      // Arrange
      const menu = createMockMenu({ isDefault: true });
      mockRepository.findDefaultMenu.mockResolvedValue(menu);

      // Act
      const result = await service.getDefaultMenu(orgId);

      // Assert
      expect(result).toEqual(menu);
      expect(mockRepository.findDefaultMenu).toHaveBeenCalledWith(orgId);
    });
  });

  // ---------------------------------------------------------------------------
  // Create Operations Tests
  // ---------------------------------------------------------------------------

  describe('create', () => {
    const validCreateData = {
      name: 'New Menu',
      description: 'A new menu',
    };

    it('should create a menu successfully', async () => {
      // Arrange
      const createdMenu = createMockMenu({
        name: validCreateData.name,
        description: validCreateData.description,
        slug: 'new-menu',
      });
      mockRepository.count.mockResolvedValue(0);
      mockRepository.slugExists.mockResolvedValue(false);
      mockRepository.create.mockResolvedValue(createdMenu);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.create(orgId, validCreateData);

      // Assert
      expect(result.menu).toEqual(createdMenu);
      expect(result.message).toContain('successfully');
      expect(mockRepository.create).toHaveBeenCalledWith(
        orgId,
        expect.objectContaining({
          name: validCreateData.name,
          slug: 'new-menu',
        })
      );
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'menu.created',
        expect.objectContaining({
          menuId: createdMenu.id,
          organizationId: orgId,
        })
      );
    });

    it('should set isDefault to true when creating first menu', async () => {
      // Arrange
      const createdMenu = createMockMenu({ isDefault: true });
      mockRepository.count.mockResolvedValue(0);
      mockRepository.slugExists.mockResolvedValue(false);
      mockRepository.create.mockResolvedValue(createdMenu);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.create(orgId, validCreateData);

      // Assert
      expect(mockRepository.create).toHaveBeenCalledWith(
        orgId,
        expect.objectContaining({ isDefault: true })
      );
    });

    it('should generate unique slug when slug already exists', async () => {
      // Arrange
      const createdMenu = createMockMenu({ slug: 'new-menu-1' });
      mockRepository.count.mockResolvedValue(1);
      mockRepository.slugExists
        .mockResolvedValueOnce(true)
        .mockResolvedValueOnce(false);
      mockRepository.create.mockResolvedValue(createdMenu);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.create(orgId, validCreateData);

      // Assert
      expect(mockRepository.create).toHaveBeenCalledWith(
        orgId,
        expect.objectContaining({ slug: 'new-menu-1' })
      );
    });

    it('should throw error when provided slug already exists', async () => {
      // Arrange
      mockRepository.slugExists.mockResolvedValue(true);

      const dataWithSlug = {
        ...validCreateData,
        slug: 'existing-slug',
      };

      // Act & Assert
      await expect(service.create(orgId, dataWithSlug)).rejects.toThrow(
        AppException
      );
    });

    it('should throw validation error for invalid input', async () => {
      // Arrange
      const invalidData = { name: '' };

      // Act & Assert
      await expect(service.create(orgId, invalidData as any)).rejects.toThrow(
        AppException
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Update Operations Tests
  // ---------------------------------------------------------------------------

  describe('update', () => {
    const validUpdateData = {
      name: 'Updated Menu',
      description: 'Updated description',
    };

    it('should update a menu successfully', async () => {
      // Arrange
      const existingMenu = createMockMenu();
      const updatedMenu = createMockMenu({
        ...existingMenu,
        name: validUpdateData.name,
        description: validUpdateData.description,
      });
      mockRepository.findByIdOrThrow.mockResolvedValue(existingMenu);
      mockRepository.update.mockResolvedValue(updatedMenu);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.update(orgId, 'menu_123', validUpdateData);

      // Assert
      expect(result.menu).toEqual(updatedMenu);
      expect(result.message).toContain('successfully');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'menu.updated',
        expect.objectContaining({
          menuId: updatedMenu.id,
          organizationId: orgId,
        })
      );
    });

    it('should throw error when menu not found', async () => {
      // Arrange
      mockRepository.findByIdOrThrow.mockRejectedValue(
        AppException.notFound('Menu', 'nonexistent')
      );

      // Act & Assert
      await expect(
        service.update(orgId, 'nonexistent', validUpdateData)
      ).rejects.toThrow(AppException);
    });

    it('should check slug uniqueness when changing slug', async () => {
      // Arrange
      const existingMenu = createMockMenu();
      mockRepository.findByIdOrThrow.mockResolvedValue(existingMenu);
      mockRepository.slugExists.mockResolvedValue(true);

      // Act & Assert
      await expect(
        service.update(orgId, 'menu_123', { slug: 'existing-slug' })
      ).rejects.toThrow(AppException);
    });
  });

  describe('updateSettings', () => {
    it('should update menu settings successfully', async () => {
      // Arrange
      const existingMenu = createMockMenu({ settings: { theme: 'light' } });
      const newSettings: MenuSettings = { theme: 'dark', layout: 'grid' };
      const updatedMenu = createMockMenu({
        settings: { theme: 'dark', layout: 'grid' },
      });
      mockRepository.findByIdOrThrow.mockResolvedValue(existingMenu);
      mockRepository.updateSettings.mockResolvedValue(updatedMenu);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.updateSettings(
        orgId,
        'menu_123',
        newSettings
      );

      // Assert
      expect(result.settings).toEqual(updatedMenu.settings);
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'menu.settings.updated',
        expect.any(Object)
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Publish Operations Tests
  // ---------------------------------------------------------------------------

  describe('publish', () => {
    it('should publish a menu successfully', async () => {
      // Arrange
      const unpublishedMenu = createMockMenu({ isPublished: false });
      const publishedMenu = createMockMenu({
        isPublished: true,
        publishedAt: new Date(),
      });
      mockRepository.findByIdOrThrow.mockResolvedValue(unpublishedMenu);
      mockRepository.publish.mockResolvedValue(publishedMenu);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.publish(orgId, 'menu_123');

      // Assert
      expect(result.menu.isPublished).toBe(true);
      expect(result.message).toContain('successfully');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'menu.published',
        expect.objectContaining({
          menuId: publishedMenu.id,
        })
      );
    });

    it('should return early if menu is already published', async () => {
      // Arrange
      const alreadyPublishedMenu = createMockMenu({ isPublished: true });
      mockRepository.findByIdOrThrow.mockResolvedValue(alreadyPublishedMenu);

      // Act
      const result = await service.publish(orgId, 'menu_123');

      // Assert
      expect(result.message).toContain('already published');
      expect(mockRepository.publish).not.toHaveBeenCalled();
    });
  });

  describe('unpublish', () => {
    it('should unpublish a menu successfully', async () => {
      // Arrange
      const publishedMenu = createMockMenu({ isPublished: true });
      const unpublishedMenu = createMockMenu({ isPublished: false });
      mockRepository.findByIdOrThrow.mockResolvedValue(publishedMenu);
      mockRepository.unpublish.mockResolvedValue(unpublishedMenu);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.unpublish(orgId, 'menu_123');

      // Assert
      expect(result.menu.isPublished).toBe(false);
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'menu.unpublished',
        expect.any(Object)
      );
    });

    it('should return early if menu is not published', async () => {
      // Arrange
      const notPublishedMenu = createMockMenu({ isPublished: false });
      mockRepository.findByIdOrThrow.mockResolvedValue(notPublishedMenu);

      // Act
      const result = await service.unpublish(orgId, 'menu_123');

      // Assert
      expect(result.message).toContain('not published');
      expect(mockRepository.unpublish).not.toHaveBeenCalled();
    });
  });

  // ---------------------------------------------------------------------------
  // Default Menu Operations Tests
  // ---------------------------------------------------------------------------

  describe('setAsDefault', () => {
    it('should set menu as default', async () => {
      // Arrange
      const menu = createMockMenu({ isDefault: true });
      mockRepository.setAsDefault.mockResolvedValue(menu);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.setAsDefault(orgId, 'menu_123');

      // Assert
      expect(result.isDefault).toBe(true);
      expect(mockRepository.setAsDefault).toHaveBeenCalledWith('menu_123', orgId);
    });
  });

  // ---------------------------------------------------------------------------
  // Duplicate Operations Tests
  // ---------------------------------------------------------------------------

  describe('duplicate', () => {
    it('should duplicate a menu successfully', async () => {
      // Arrange
      const originalMenu = createMockMenu();
      const duplicatedMenu = createMockMenu({
        id: 'menu_456',
        name: 'Copy of Test Menu',
        slug: 'copy-of-test-menu',
        isDefault: false,
        isPublished: false,
      });
      mockRepository.findByIdOrThrow.mockResolvedValue(originalMenu);
      mockRepository.slugExists.mockResolvedValue(false);
      mockRepository.duplicate.mockResolvedValue(duplicatedMenu);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.duplicate(
        orgId,
        'menu_123',
        'Copy of Test Menu'
      );

      // Assert
      expect(result.menu).toEqual(duplicatedMenu);
      expect(result.message).toContain('successfully');
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'menu.created',
        expect.objectContaining({
          duplicatedFrom: 'menu_123',
        })
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Delete Operations Tests
  // ---------------------------------------------------------------------------

  describe('delete', () => {
    it('should soft delete a menu successfully', async () => {
      // Arrange
      const menu = createMockMenu({ isDefault: false });
      mockRepository.findByIdOrThrow.mockResolvedValue(menu);
      mockRepository.count.mockResolvedValue(2);
      mockRepository.softDelete.mockResolvedValue(undefined);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      await service.delete(orgId, 'menu_123');

      // Assert
      expect(mockRepository.softDelete).toHaveBeenCalledWith('menu_123', orgId);
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'menu.deleted',
        expect.objectContaining({
          menuId: menu.id,
        })
      );
    });

    it('should throw error when trying to delete the only menu', async () => {
      // Arrange
      const menu = createMockMenu();
      mockRepository.findByIdOrThrow.mockResolvedValue(menu);
      mockRepository.count.mockResolvedValue(1);

      // Act & Assert
      await expect(service.delete(orgId, 'menu_123')).rejects.toThrow(
        AppException
      );
      expect(mockRepository.softDelete).not.toHaveBeenCalled();
    });

    it('should throw error when trying to delete the default menu', async () => {
      // Arrange
      const menu = createMockMenu({ isDefault: true });
      mockRepository.findByIdOrThrow.mockResolvedValue(menu);
      mockRepository.count.mockResolvedValue(2);

      // Act & Assert
      await expect(service.delete(orgId, 'menu_123')).rejects.toThrow(
        AppException
      );
      expect(mockRepository.softDelete).not.toHaveBeenCalled();
    });
  });

  describe('restore', () => {
    it('should restore a soft-deleted menu', async () => {
      // Arrange
      const restoredMenu = createMockMenu();
      mockRepository.restore.mockResolvedValue(restoredMenu);
      mockEventService.emitCustom.mockResolvedValue(undefined);

      // Act
      const result = await service.restore(orgId, 'menu_123');

      // Assert
      expect(result).toEqual(restoredMenu);
      expect(mockEventService.emitCustom).toHaveBeenCalledWith(
        'menu.restored',
        expect.any(Object)
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Validation Operations Tests
  // ---------------------------------------------------------------------------

  describe('isSlugAvailable', () => {
    it('should return true when slug is available', async () => {
      // Arrange
      mockRepository.slugExists.mockResolvedValue(false);

      // Act
      const result = await service.isSlugAvailable(orgId, 'available-slug');

      // Assert
      expect(result).toBe(true);
    });

    it('should return false when slug is taken', async () => {
      // Arrange
      mockRepository.slugExists.mockResolvedValue(true);

      // Act
      const result = await service.isSlugAvailable(orgId, 'taken-slug');

      // Assert
      expect(result).toBe(false);
    });

    it('should exclude current menu when checking slug', async () => {
      // Arrange
      mockRepository.slugExists.mockResolvedValue(false);

      // Act
      await service.isSlugAvailable(orgId, 'current-slug', 'menu_123');

      // Assert
      expect(mockRepository.slugExists).toHaveBeenCalledWith(
        orgId,
        'current-slug',
        'menu_123'
      );
    });
  });

  describe('count', () => {
    it('should return menu count', async () => {
      // Arrange
      mockRepository.count.mockResolvedValue(5);

      // Act
      const result = await service.count(orgId);

      // Assert
      expect(result).toBe(5);
    });

    it('should filter by published status', async () => {
      // Arrange
      mockRepository.count.mockResolvedValue(3);

      // Act
      await service.count(orgId, true);

      // Assert
      expect(mockRepository.count).toHaveBeenCalledWith(orgId, true);
    });
  });
});
